  1→using System.IO.Ports;
  2→
  3→namespace DiffTest
  4→{
  5→    /// <summary>
  6→    /// 바코드 스캐너 통신 클래스
  7→    /// </summary>
  8→    public class BarcodeScanner : Devices.Abstractions.IBarcodeScanner
  9→    {
 10→        private SerialPort? _serialPort;
 11→        private bool _disposed;
 12→
 13→        /// <summary>
 14→        /// 스캔 데이터 수신 이벤트
 15→        /// </summary>
 16→        public event EventHandler<string>? DataReceived;
 17→
 18→        /// <summary>
 19→        /// 연결 상태
 20→        /// </summary>
 21→        public bool IsConnected => _serialPort?.IsOpen ?? false;
 22→
 23→        /// <summary>
 24→        /// 포트 이름
 25→        /// </summary>
 26→        public string PortName { get; private set; } = string.Empty;
 27→
 28→        /// <summary>
 29→        /// 바코드 스캐너 연결
 30→        /// </summary>
 31→        /// <param name="portName">COM 포트명 (예: COM1)</param>
 32→        /// <param name="baudRate">통신 속도 (기본: 9600)</param>
 33→        /// <returns>연결 성공 여부</returns>
 34→        public bool Connect(string portName, int baudRate = 9600)
 35→        {
 36→            LogHelper.Instance.Log("Scanner", $"Connect 시도: Port={portName}, BaudRate={baudRate}");
 37→
 38→            if (string.IsNullOrEmpty(portName) || portName == "Disabled")
 39→            {
 40→                LogHelper.Instance.Log("Scanner", $"Connect 중단: 포트 Disabled 또는 비어있음");
 41→                return false;
 42→            }
 43→
 44→            // 실제 포트 존재 여부 확인
 45→            var availablePorts = SerialPort.GetPortNames();
 46→            if (!availablePorts.Contains(portName))
 47→            {
 48→                LogHelper.Instance.Log("Scanner", $"Connect 실패: 포트 {portName} 없음 (사용가능: {string.Join(",", availablePorts)})");
 49→                return false;
 50→            }
 51→
 52→            try
 53→            {
 54→                Disconnect();
 55→
 56→                _serialPort = new SerialPort
 57→                {
 58→                    PortName = portName,
 59→                    BaudRate = baudRate,
 60→                    DataBits = 8,
 61→                    Parity = Parity.None,
 62→                    StopBits = StopBits.One,
 63→                    ReadTimeout = 1000,
 64→                    WriteTimeout = 1000
 65→                };
 66→
 67→                _serialPort.DataReceived += OnDataReceived;
 68→                _serialPort.Open();
 69→                PortName = portName;
 70→
 71→                LogHelper.Instance.Log("Scanner", $"Connect 성공: Port={portName}");
 72→                return true;
 73→            }
 74→            catch (UnauthorizedAccessException ex)
 75→            {
 76→                LogHelper.Instance.LogError("Scanner", $"포트 {portName} 접근 거부 (다른 프로그램이 사용 중)", ex);
 77→                return false;
 78→            }
 79→            catch (System.IO.IOException ex)
 80→            {
 81→                LogHelper.Instance.LogError("Scanner", $"포트 {portName} IO 오류", ex);
 82→                return false;
 83→            }
 84→            catch (Exception ex)
 85→            {
 86→                LogHelper.Instance.LogError("Scanner", $"Connect 예외: {ex.GetType().Name}", ex);
 87→                return false;
 88→            }
 89→        }
 90→
 91→        /// <summary>
 92→        /// 연결 종료
 93→        /// </summary>
 94→        public void Disconnect()
 95→        {
 96→            if (_serialPort != null)
 97→            {
 98→                if (_serialPort.IsOpen)
 99→                {
100→                    _serialPort.DataReceived -= OnDataReceived;
101→                    _serialPort.Close();
102→                }
103→                _serialPort.Dispose();
104→                _serialPort = null;
105→            }
106→        }
107→
108→        private void OnDataReceived(object sender, SerialDataReceivedEventArgs e)
109→        {
110→            try
111→            {
112→                if (_serialPort == null || !_serialPort.IsOpen)
113→                    return;
114→
115→                var incoming = _serialPort.ReadLine();
116→                // 마지막 문자(CR) 제거
117→                var scanData = incoming.Length > 1 ? incoming[..^1] : incoming;
118→
119→                DataReceived?.Invoke(this, scanData);
120→            }
121→            catch (TimeoutException ex)
122→            {
123→                LogHelper.Instance.LogError("Scanner", $"수신 타임아웃 Port={PortName}", ex);
124→            }
125→            catch (Exception ex)
126→            {
127→                LogHelper.Instance.LogError("Scanner", $"수신 오류 Port={PortName}: {ex.GetType().Name}", ex);
128→            }
129→        }
130→
131→        public void Dispose()
132→        {
133→            Dispose(true);
134→            GC.SuppressFinalize(this);
135→        }
136→
137→        protected virtual void Dispose(bool disposing)
138→        {
139→            if (_disposed) return;
140→            if (disposing)
141→            {
142→                Disconnect();
143→            }
144→            _disposed = true;
145→        }
146→    }
147→}
