using System.IO.Ports;
using System.Text;

namespace DiffTest
{
    /// <summary>
    /// 바코드 라벨 생성 및 프린터 전송 서비스
    /// FrmMain에서 분리된 독립 클래스
    /// </summary>
    public class BarcodeService
    {
        private readonly MeasureData _data;
        private readonly SerialPort? _printerLH;
        private readonly SerialPort? _printerRH;

        public BarcodeService(MeasureData data, SerialPort? printerLH, SerialPort? printerRH)
        {
            _data = data;
            _printerLH = printerLH;
            _printerRH = printerRH;
        }

        /// <summary>
        /// 바코드 라벨 출력 (OK)
        /// VB 원본: 2D 바코드 포맷 + DIFF 평균값 출력
        /// </summary>
        public void BarcodePrint(string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[OK] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // 2D 바코드 데이터 생성 (VB 원본 포맷)
                // ZPL ^FH 명령이 _XX를 hex로 해석하므로 문자열 그대로 전송
                const string RS = "_1e";   // Record Separator (^FH가 해석)
                const string GS = "_1d";   // Group Separator (^FH가 해석)
                const string EOT = "_04";  // End of Transmission (^FH가 해석)

                string partNoClean = partNo.Replace("-", "");
                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";

                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";

                // DIFF 평균값 계산
                string diffData = CalcDiffAverageString(side);

                // 바코드 사이즈 (+2 VB 원본)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL 생성
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{diffData}^FS");
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[OK] ZPL 생성: {zpl.Length}자, diffData={diffData}");

                // 프린터 전송
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[OK] 출력 오류: side={side}", ex);
            }
        }

        /// <summary>
        /// NG 바코드 라벨 출력
        /// VB 원본: 바코드에 NG 접두어 + TQ 필드에 "NG" 출력
        /// </summary>
        public void BarcodePrintNG(string ngMessage, string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[NG] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}, msg={ngMessage}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // 바코드 데이터: NG + 시리얼 (VB 원본)
                string barcodeData = "NG" + serialNo;

                // 바코드 사이즈 (+2 VB 원본)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL 생성 (TQ 필드에 "NG" 추가)
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{ngMessage}^FS");
                sb.Append($"^FO{bs.TqX},{bs.TqY}^A0N,{bs.TqH},{bs.TqW}^FDNG^FS");
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[NG] ZPL 생성: {zpl.Length}자");

                // 프린터 전송
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[NG] 출력 오류: side={side}", ex);
            }
        }

        /// <summary>
        /// 강제 라벨 출력 (FrmBarcode에서 호출)
        /// </summary>
        public void ManualBarcodePrint(string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[Manual] 출력 시작: side={side}, partNo={partNo}, serial={serialNo}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // 2D 바코드 데이터 생성
                const string RS = "_1e";
                const string GS = "_1d";
                const string EOT = "_04";

                string partNoClean = partNo.Replace("-", "");
                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";

                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";

                // 바코드 사이즈 (+2 VB 원본)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL 생성
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD ^FS");  // 강제출력은 빈값
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[Manual] ZPL 생성: {zpl.Length}자");

                // 프린터 전송
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[Manual] 출력 오류: side={side}", ex);
            }
        }

        /// <summary>
        /// DIFF 평균값 문자열 생성
        /// VB 원본: "F:{fwd}mm B:{bwd}mm D:{end}mm Lever:{lever}Kg"
        /// </summary>
        public string CalcDiffAverageString(string side)
        {
            try
            {
                double fwdSum = 0, bwdSum = 0, endSum = 0;
                int fwdCnt = 0, bwdCnt = 0, endCnt = 0;

                for (int i = 0; i < 5; i++)
                {
                    if (!string.IsNullOrEmpty(_data.ValDiffFwd[i]) && double.TryParse(_data.ValDiffFwd[i], out double fv))
                    {
                        fwdSum += fv; fwdCnt++;
                    }
                    if (!string.IsNullOrEmpty(_data.ValDiffBwd[i]) && double.TryParse(_data.ValDiffBwd[i], out double bv))
                    {
                        bwdSum += bv; bwdCnt++;
                    }
                    if (!string.IsNullOrEmpty(_data.ValDiffEnd[i]) && double.TryParse(_data.ValDiffEnd[i], out double ev))
                    {
                        endSum += ev; endCnt++;
                    }
                }

                string fwdAvg = fwdCnt > 0 ? (fwdSum / fwdCnt).ToString("F1") : "0.0";
                string bwdAvg = bwdCnt > 0 ? (bwdSum / bwdCnt).ToString("F1") : "0.0";
                string endAvg = endCnt > 0 ? (endSum / endCnt).ToString("F1") : "0.0";

                string lever = (side == "A" || side == "RH")
                    ? _data.ValueLever.ToString("F1")
                    : _data.ValueLeverB.ToString("F1");

                // WAV 사양은 각도(°) 표기, 그 외는 Kg 표기
                string optionType = (side == "A" || side == "LH") ? _data.OptionTypeA : _data.OptionTypeB;
                string leverUnit = optionType == "3-WAV" ? "°" : "Kg";

                return $"F:{fwdAvg}mm B:{bwdAvg}mm D:{endAvg}mm Lever:{lever}{leverUnit}";
            }
            catch
            {
                return "";
            }
        }

        /// <summary>
        /// 프린터로 ZPL 전송
        /// </summary>
        private void SendToPrinter(SerialPort? printer, string zpl, string printerName)
        {
            if (printer == null || !printer.IsOpen)
            {
                LogHelper.Instance.Log("Barcode", $"프린터 미연결: {printerName}");
                return;
            }

            try
            {
                printer.Write(zpl);
                LogHelper.Instance.Log("Barcode", $"프린터 전송 완료: {printerName}, port={printer.PortName}");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"프린터 전송 오류: {printerName}", ex);
            }
        }
    }
}

