namespace DiffTest
{
    /// <summary>
    /// 바코드 라벨 좌표 설정 폼
    /// PropertyGrid 사용 + 강제 라벨 출력
    /// </summary>
    public partial class FrmBarcode : Form
    {
        // FrmMain 참조 (라벨 출력용)
        private FrmMain? _frmMain;

        public FrmBarcode()
        {
            InitializeComponent();
        }

        /// <summary>
        /// FrmMain 참조 설정
        /// </summary>
        public void SetMainForm(FrmMain frm)
        {
            _frmMain = frm;
        }

        private void FrmBarcode_Load(object sender, EventArgs e)
        {
            // DB에서 바코드 설정 로드
            try
            {
                MdbHelper.LoadBarcodeData();
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, $"바코드 설정 로드 실패: {ex.Message}", "오류",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }

            // PropertyGrid에 설정 객체 바인딩
            propertyGrid1.SelectedObject = BarcodeSettings.Instance;

            // 콤보박스 초기화
            LoadPartNoCombo();
            LoadColorCombo();
            cboPrinter.SelectedIndex = 0;  // 기본 LH
        }

        /// <summary>
        /// Table_Part에서 PartNo 로드
        /// </summary>
        private void LoadPartNoCombo()
        {
            try
            {
                var partList = SqlHelper.LoadAllPartNo();
                cboPartNo.Items.Clear();
                foreach (var partNo in partList)
                {
                    cboPartNo.Items.Add(partNo);
                }
                if (cboPartNo.Items.Count > 0)
                    cboPartNo.SelectedIndex = 0;
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"LoadPartNoCombo Error: {ex.Message}");
            }
        }

        /// <summary>
        /// 모든 Table_Color_* 테이블에서 ColorCode 로드 (중복 제거)
        /// </summary>
        private void LoadColorCombo()
        {
            try
            {
                var colorList = SqlHelper.LoadAllColorCodes();
                cboColor.Items.Clear();
                foreach (var color in colorList)
                {
                    cboColor.Items.Add(color);
                }
                if (cboColor.Items.Count > 0)
                    cboColor.SelectedIndex = 0;
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"LoadColorCombo Error: {ex.Message}");
            }
        }

        private void btnSave_Click(object sender, EventArgs e)
        {
            try
            {
                MdbHelper.SaveBarcodeData();
                MessageBox.Show(this, "바코드 설정이 저장되었습니다.", "저장 완료",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex)
            {
                MessageBox.Show(this, $"저장 실패: {ex.Message}", "오류",
                    MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private void btnClose_Click(object sender, EventArgs e)
        {
            Close();
        }

        private void btnTestPrint_Click(object sender, EventArgs e)
        {
            if (string.IsNullOrWhiteSpace(txtTestBarcode.Text))
            {
                MessageBox.Show(this, "테스트 바코드를 입력하세요.", "알림",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            // TODO: 테스트 출력 구현
            MessageBox.Show(this, $"테스트 바코드: {txtTestBarcode.Text}", "테스트 출력",
                MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        /// <summary>
        /// 강제 라벨 출력
        /// </summary>
        private void btnManualPrint_Click(object sender, EventArgs e)
        {
            // 입력 검증
            if (cboPartNo.SelectedItem == null)
            {
                MessageBox.Show(this, "PartNo를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            if (cboColor.SelectedItem == null)
            {
                MessageBox.Show(this, "Color를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            if (!int.TryParse(txtLotStart.Text, out int lotStart) || lotStart < 1)
            {
                MessageBox.Show(this, "Lot 시작번호를 올바르게 입력하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            if (!int.TryParse(txtQty.Text, out int qty) || qty < 1)
            {
                MessageBox.Show(this, "수량을 올바르게 입력하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            if (cboPrinter.SelectedItem == null)
            {
                MessageBox.Show(this, "프린터를 선택하세요.", "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            string partNo = cboPartNo.SelectedItem.ToString() ?? "";
            string colorCode = cboColor.SelectedItem.ToString() ?? "";
            string dateStr = dtpDate.Value.ToString("yyyyMMdd");
            string printer = cboPrinter.SelectedItem.ToString() ?? "LH";
            string side = printer == "LH" ? "B" : "A";

            // PartName 조회
            string partName = SqlHelper.GetPartName(partNo);

            // 수량만큼 출력
            for (int i = 0; i < qty; i++)
            {
                int lotNum = lotStart + i;
                // 시리얼번호: 날짜(8) + LOT번호(7) + PartNo
                string serialNo = dateStr + lotNum.ToString("0000000") + partNo;

                // FrmMain의 BarcodePrint 호출
                _frmMain?.ManualBarcodePrint(partNo + colorCode, partName, serialNo, side);
            }

            MessageBox.Show(this, $"{qty}장 출력 완료", "출력 완료", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
    }
}

