        public static DataTable LoadSensorMappings(string angleType, string? basicType = null)
        {
            // 원본: 문자열 직접 조합 (SQL Injection 취약)
            if (string.IsNullOrEmpty(basicType))
            {
                var sql = "SELECT * FROM Table_SensorMapping WHERE AngleType = ? AND (BasicType IS NULL OR BasicType = '') ORDER BY SensorIndex";
                return ExecuteQuery(sql, new OleDbParameter("@p1", angleType));
            }
            else
            {
                var sql = "SELECT * FROM Table_SensorMapping WHERE AngleType = ? AND BasicType = ? ORDER BY SensorIndex";
                return ExecuteQuery(sql,
                    new OleDbParameter("@p1", angleType),
                    new OleDbParameter("@p2", basicType));
            }
        }

