using System.Data;
using System.Data.OleDb;

namespace DiffTest
{
    /// <summary>
    /// Access MDB 데이터베이스 헬퍼 클래스
    /// ACE.OLEDB.12.0 사용 (Access Database Engine 64bit 필요)
    /// </summary>
    public static class MdbHelper
    {
        private static string? _connectionString;

        /// <summary>
        /// DB 연결 문자열 (자동 초기화)
        /// </summary>
        public static string ConnectionString
        {
            get
            {
                if (_connectionString == null)
                {
                    var dbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", "DB.mdb");
                    _connectionString = $"Provider=Microsoft.ACE.OLEDB.12.0;Data Source={dbPath};";
                }
                return _connectionString;
            }
        }

        /// <summary>
        /// 연결 생성
        /// </summary>
        public static OleDbConnection CreateConnection()
        {
            return new OleDbConnection(ConnectionString);
        }

        /// <summary>
        /// SELECT 쿼리 실행 후 DataTable 반환
        /// </summary>
        public static DataTable ExecuteQuery(string sql, params OleDbParameter[] parameters)
        {
            var dt = new DataTable();
            using var conn = CreateConnection();
            using var cmd = new OleDbCommand(sql, conn);
            if (parameters != null && parameters.Length > 0)
                cmd.Parameters.AddRange(parameters);
            using var adapter = new OleDbDataAdapter(cmd);
            conn.Open();
            adapter.Fill(dt);
            return dt;
        }

        /// <summary>
        /// INSERT/UPDATE/DELETE 쿼리 실행
        /// </summary>
        public static int ExecuteNonQuery(string sql, params OleDbParameter[] parameters)
        {
            using var conn = CreateConnection();
            using var cmd = new OleDbCommand(sql, conn);
            if (parameters != null && parameters.Length > 0)
                cmd.Parameters.AddRange(parameters);
            conn.Open();
            return cmd.ExecuteNonQuery();
        }

        /// <summary>
        /// 스칼라 값 반환 쿼리 실행
        /// </summary>
        public static object? ExecuteScalar(string sql, params OleDbParameter[] parameters)
        {
            using var conn = CreateConnection();
            using var cmd = new OleDbCommand(sql, conn);
            if (parameters != null && parameters.Length > 0)
                cmd.Parameters.AddRange(parameters);
            conn.Open();
            return cmd.ExecuteScalar();
        }

        /// <summary>
        /// 테이블에 컬럼이 존재하는지 확인
        /// </summary>
        public static bool ColumnExists(string tableName, string columnName)
        {
            try
            {
                using var conn = CreateConnection();
                conn.Open();
                var schema = conn.GetSchema("Columns", new[] { null, null, tableName, columnName });
                return schema.Rows.Count > 0;
            }
            catch
            {
                return false;
            }
        }

        /// <summary>
        /// 테이블에 컬럼 추가 (없으면)
        /// </summary>
        public static void EnsureColumn(string tableName, string columnName, string columnType, object? defaultValue = null)
        {
            if (ColumnExists(tableName, columnName)) return;

            try
            {
                string sql = $"ALTER TABLE [{tableName}] ADD COLUMN [{columnName}] {columnType}";
                ExecuteNonQuery(sql);

                // 기본값 설정
                if (defaultValue != null)
                {
                    string updateSql = $"UPDATE [{tableName}] SET [{columnName}] = ?";
                    ExecuteNonQuery(updateSql, new OleDbParameter("@val", defaultValue));
                }

                LogHelper.Instance.Log("MdbHelper", $"컬럼 추가: {tableName}.{columnName} ({columnType}) 기본값={defaultValue}");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("MdbHelper", $"컬럼 추가 실패: {tableName}.{columnName}", ex);
            }
        }

