        /// <summary>
        /// Table_PLC에서 신호 이름 로드
        /// </summary>
        /// <returns>IN 신호 이름 64개, OUT 신호 이름 64개</returns>
        public static (string[] inNames, string[] outNames) LoadPlcSignalNames()
        {
            var inNames = new string[64];
            var outNames = new string[64];

            // 기본값 초기화
            for (int i = 0; i < 64; i++)
            {
                inNames[i] = $"IN_{i:D2}";
                outNames[i] = $"OUT_{i:D2}";
            }

            try
            {
                // 기존 VB 방식: ORDER BY LEN(ID), ID
                var dt = ExecuteQuery("SELECT * FROM Table_PLC ORDER BY LEN(ID), ID");

                foreach (DataRow row in dt.Rows)
                {
                    var id = GetString(row, "ID");
                    var name = GetString(row, "Name");

                    if (id.StartsWith("P_IN_") && int.TryParse(id.Substring(5), out int inIdx))
                    {
                        if (inIdx >= 0 && inIdx < 64)
                            inNames[inIdx] = string.IsNullOrEmpty(name) ? $"IN_{inIdx:D2}" : name;
                    }
                    else if (id.StartsWith("P_OUT_") && int.TryParse(id.Substring(6), out int outIdx))
                    {
                        if (outIdx >= 0 && outIdx < 64)
                            outNames[outIdx] = string.IsNullOrEmpty(name) ? $"OUT_{outIdx:D2}" : name;
                    }
                }
            }
            catch
            {
                // DB 오류 시 기본값 사용
            }

            return (inNames, outNames);
        }

