                new OleDbParameter("@p52", settings.BwdTolLH2),
                new OleDbParameter("@p53", settings.BwdTolLH3),
                new OleDbParameter("@p54", settings.BwdTolRH1),
                new OleDbParameter("@p55", settings.BwdTolRH2),
                new OleDbParameter("@p56", settings.BwdTolRH3),
                new OleDbParameter("@p57", settings.TqCalVal1),
                new OleDbParameter("@p58", settings.TqCalVal2),
                new OleDbParameter("@p59", settings.TqCalVal3),
                new OleDbParameter("@p60", settings.TqTolLH),
                new OleDbParameter("@p61", settings.TqTolRH),
                // FWD 센서
                new OleDbParameter("@p62", settings.FwdSensorLH1Use ? -1 : 0),
                new OleDbParameter("@p63", settings.FwdSensorLH2Use ? -1 : 0),
                new OleDbParameter("@p64", settings.FwdSensorLH3Use ? -1 : 0),
                new OleDbParameter("@p65", settings.FwdSensorRH1Use ? -1 : 0),
                new OleDbParameter("@p66", settings.FwdSensorRH2Use ? -1 : 0),
                new OleDbParameter("@p67", settings.FwdSensorRH3Use ? -1 : 0),
                // BWD 센서
                new OleDbParameter("@p68", settings.BwdSensorLH1Use ? -1 : 0),
                new OleDbParameter("@p69", settings.BwdSensorLH2Use ? -1 : 0),
                new OleDbParameter("@p70", settings.BwdSensorLH3Use ? -1 : 0),
                new OleDbParameter("@p71", settings.BwdSensorRH1Use ? -1 : 0),
                new OleDbParameter("@p72", settings.BwdSensorRH2Use ? -1 : 0),
                new OleDbParameter("@p73", settings.BwdSensorRH3Use ? -1 : 0),
                // 칼라 센서
                new OleDbParameter("@p74", settings.ColorUse ? -1 : 0),
                new OleDbParameter("@p75", settings.CheckColor1 ? -1 : 0),
