                new OleDbParameter("@p82", settings.DiffBwdOffset),
                new OleDbParameter("@p83", settings.DiffEndOffset),
                new OleDbParameter("@p84", basicType));
        }

        #endregion

        #region 보간 테이블

        /// <summary>
        /// 보간 테이블 로드 (파라미터 바인딩 사용)
        /// </summary>
        public static DataTable LoadAngleTable(string angleType, string basicType)
        {
            var tableName = GetAngleTableName(angleType);
            // 원본: 문자열 직접 조합 (SQL Injection 취약)
            // 테이블명은 화이트리스트로 검증됨 (GetAngleTableName)
            return ExecuteQuery($"SELECT * FROM {tableName} WHERE Type = ? ORDER BY LaserDistance ASC",
                new OleDbParameter("@p1", basicType));
        }

        /// <summary>
        /// 보간 테이블 저장 (전체 교체, 파라미터 바인딩 사용)
        /// </summary>
        public static void SaveAngleTable(string angleType, string basicType, List<(double laserDistance, double convertAngle)> data)
        {
            var tableName = GetAngleTableName(angleType);

            // 원본: 문자열 직접 조합 (SQL Injection 취약)
            // 기존 데이터 삭제
            ExecuteNonQuery($"DELETE FROM {tableName} WHERE Type = ?",
                new OleDbParameter("@p1", basicType));

            // 새 데이터 삽입
            foreach (var (laserDistance, convertAngle) in data)
            {
                ExecuteNonQuery($"INSERT INTO {tableName} (Type, LaserDistance, ConvertAngle) VALUES (?, ?, ?)",
                    new OleDbParameter("@p1", basicType),
                    new OleDbParameter("@p2", laserDistance),
                    new OleDbParameter("@p3", convertAngle));
            }
        }

        /// <summary>
        /// AngleType에 대응하는 테이블명 반환 (화이트리스트 검증)
        /// </summary>
        private static string GetAngleTableName(string angleType)
        {
            return angleType switch
            {
                "LH_FWD" => "Table_Angle_LH_FWD",
                "LH_BWD" => "Table_Angle_LH_BWD",
                "RH_FWD" => "Table_Angle_RH_FWD",
                "RH_BWD" => "Table_Angle_RH_BWD",
                _ => throw new ArgumentException($"잘못된 AngleType: {angleType}")
            };
        }

        #endregion

        #region 헬퍼 메서드

        private static string GetString(DataRow row, string columnName)
        {
            try
            {
                var val = row[columnName];
                return val == DBNull.Value ? "" : val?.ToString() ?? "";
            }
            catch
            {
                return "";
            }
        }

        private static int GetInt(DataRow row, string columnName)
        {
            try
            {
                var val = row[columnName];
                if (val == DBNull.Value) return 0;
                return int.TryParse(val?.ToString(), out var result) ? result : 0;
            }
            catch
            {
                return 0;
            }
        }

        private static double GetDouble(DataRow row, string columnName)
        {
            try
            {
                var val = row[columnName];
                if (val == DBNull.Value) return 0;
                return double.TryParse(val?.ToString(), out var result) ? result : 0;
            }
            catch
            {
                return 0;
            }
        }

        private static double GetDoubleWithDefault(DataRow row, string columnName, double defaultValue)
        {
            try
            {
                if (!row.Table.Columns.Contains(columnName)) return defaultValue;
                var val = row[columnName];
                if (val == DBNull.Value) return defaultValue;
                return double.TryParse(val?.ToString(), out var result) ? result : defaultValue;
            }
            catch
            {
                return defaultValue;
            }
        }

        private static bool GetBool(DataRow row, string columnName)
        {
            try
            {
                var val = row[columnName];
                if (val == DBNull.Value) return false;
                if (val is bool b) return b;
                return bool.TryParse(val?.ToString(), out var result) && result;
            }
            catch
            {
                return false;
            }
        }

        #endregion

        #region NG 로그 관리

        /// <summary>
        /// NG 로그 테이블 생성 (없을 경우)
        /// </summary>
        public static void CreateNgLogTableIfNotExists()
        {
            try
            {
                // 테이블 존재 확인 (직접 조회 시도)
                try
                {
                    string checkSql = "SELECT COUNT(*) FROM Table_NG_Log";
                    ExecuteScalar(checkSql);
                    LogHelper.Instance.Log("MdbHelper", "Table_NG_Log 테이블이 이미 존재합니다");
                    return;
                }
                catch
                {
                    // 테이블이 없으면 예외 발생 - 아래에서 생성
                }

                // 테이블 생성
                string createSql = @"
                    CREATE TABLE Table_NG_Log (
                        LogID AUTOINCREMENT PRIMARY KEY,
                        LogDateTime DATETIME,
                        Side TEXT(10),
                        MeasureType TEXT(10),
                        AngleValue DOUBLE,
                        MinSpec DOUBLE,
                        MaxSpec DOUBLE,
                        SerialNo TEXT(50),
                        PartNo TEXT(50),
                        PartName TEXT(100),
                        Result TEXT(10)
                    )";

                ExecuteNonQuery(createSql);
                LogHelper.Instance.Log("MdbHelper", "Table_NG_Log 테이블 생성 완료");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("MdbHelper", "NG 로그 테이블 생성 실패", ex);
            }
        }

        /// <summary>
        /// NG 로그 저장
        /// </summary>
        public static void SaveNgLog(string side, string measureType, double angleValue,
            double minSpec, double maxSpec, string serialNo, string partNo, string partName)
        {
            try
            {
                string sql = @"
                    INSERT INTO Table_NG_Log
                    (LogDateTime, Side, MeasureType, AngleValue, MinSpec, MaxSpec, SerialNo, PartNo, PartName, Result)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";

                ExecuteNonQuery(sql,
                    new OleDbParameter("@p1", DateTime.Now),
                    new OleDbParameter("@p2", side),
                    new OleDbParameter("@p3", measureType),
                    new OleDbParameter("@p4", angleValue),
                    new OleDbParameter("@p5", minSpec),
                    new OleDbParameter("@p6", maxSpec),
                    new OleDbParameter("@p7", serialNo),
                    new OleDbParameter("@p8", partNo),
                    new OleDbParameter("@p9", partName),
                    new OleDbParameter("@p10", "NG"));

                LogHelper.Instance.Log("MdbHelper", $"NG 로그 저장 완료 {side} {measureType} {angleValue:F1}°");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("MdbHelper", "NG 로그 저장 실패", ex);
            }
        }

        /// <summary>
        /// NG 로그 조회 (날짜 범위)
        /// </summary>
        public static DataTable GetNgLogs(DateTime startDate, DateTime endDate)
        {
            try
            {
                string sql = @"
                    SELECT LogID, LogDateTime, Side, MeasureType, AngleValue, MinSpec, MaxSpec,
                           SerialNo, PartNo, PartName, Result
                    FROM Table_NG_Log
                    WHERE LogDateTime >= ? AND LogDateTime < ?
                    ORDER BY LogDateTime DESC";

                return ExecuteQuery(sql,
                    new OleDbParameter("@p1", startDate),
                    new OleDbParameter("@p2", endDate.AddDays(1)));
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("MdbHelper", "NG 로그 조회 실패", ex);
                return new DataTable();
            }
        }

        /// <summary>
        /// NG 로그 조회 (시리얼 번호)
        /// </summary>
        public static DataTable GetNgLogsBySerial(string serialNo)
        {
            try
            {
                string sql = @"
                    SELECT LogID, LogDateTime, Side, MeasureType, AngleValue, MinSpec, MaxSpec,
                           SerialNo, PartNo, PartName, Result
                    FROM Table_NG_Log
                    WHERE SerialNo LIKE ?
                    ORDER BY LogDateTime DESC";

                return ExecuteQuery(sql, new OleDbParameter("@p1", $"%{serialNo}%"));
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("MdbHelper", "NG 로그 조회 실패", ex);
                return new DataTable();
            }
        }

        #endregion
    }
}

