using System.Data;
using Microsoft.Data.SqlClient;

namespace DiffTest
{
    /// <summary>
    /// SQL Server 헬퍼 클래스
    /// 비동기 쿼리 지원
    /// </summary>
    public static partial class SqlHelper
    {
        private static string? _connectionString;
        private static List<string>? _searchableColumns;
        private static bool _indexChecked = false;

        /// <summary>
        /// 연결 문자열 설정
        /// SSL 인증서 오류 방지를 위해 TrustServerCertificate=True 및 Encrypt=Optional 자동 추가
        /// </summary>
        public static void SetConnectionString(string connStr)
        {
            if (string.IsNullOrEmpty(connStr))
            {
                _connectionString = null;
                return;
            }

            // SSL 인증서 오류 방지: TrustServerCertificate=True 및 Encrypt=False 설정
            var builder = new SqlConnectionStringBuilder(connStr);

            // TrustServerCertificate=True: SSL 인증서 검증 건너뛰기
            builder.TrustServerCertificate = true;

            // Encrypt=False: 암호화 없이 연결 (SSL 인증서 검증 불필요)
            // 이렇게 설정하면 SSL 인증서 오류를 피할 수 있음
            builder.Encrypt = false;

            _connectionString = builder.ConnectionString;

            _searchableColumns = null; // 컬럼 캐시 초기화

            // 로그에 연결 문자열 일부만 표시 (비밀번호 제외)
            var safeConnectionString = _connectionString;
            if (!string.IsNullOrEmpty(builder.Password))
            {
                safeConnectionString = safeConnectionString.Replace(builder.Password, "*****");
            }
            LogHelper.Instance.Log("SqlHelper", $"연결 문자열 설정 완료 (TrustServerCertificate=True, Encrypt=False 적용)");
            LogHelper.Instance.Log("SqlHelper", $"최종 연결 문자열: {safeConnectionString}");
        }

        /// <summary>
        /// 연결 문자열 가져오기
        /// </summary>
        public static string ConnectionString => _connectionString ?? "";

        /// <summary>
        /// 연결 테스트
        /// </summary>
        public static async Task<bool> TestConnectionAsync()
        {
            if (string.IsNullOrEmpty(_connectionString)) return false;

            try
            {
                using var conn = new SqlConnection(_connectionString);
                await conn.OpenAsync();
                return true;
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", $"TestConnectionAsync 실패: {ex.Message}", ex);
                return false;
            }
        }

        /// <summary>
        /// 인덱스 존재 여부 확인 및 생성 (최초 1회만 실행)
        /// </summary>
        public static async Task EnsureIndexesAsync()
        {
            if (_indexChecked || string.IsNullOrEmpty(_connectionString)) return;

            try
            {
                using var conn = new SqlConnection(_connectionString);
                await conn.OpenAsync();

                // TABLE_MAIN 바코드/시리얼 컬럼 인덱스 생성
                string[] barcodeColumns = [
                    "SerialNo",
                    "PartNo",
                    "OP10_BUCKLE_BARCODE",
                    "OP10_CTR_BUCKLE_BARCODE",
                    "OP10_CUSHLEG_BARCODE",
                    "OP10_BACKFRAME_BARCODE",
                    "OP10_BACKFRAME_BARCODE2",
                    "OP10_CTRBUCKLE_BARCODE",
                    "OP20_Inject_LH_BARCODE",
                    "Inject_RH_BARCODE",
                    "OP20_ECU_BARCODE",
                    "OP30_CUSH_BARCODE",
                    "OP30_HARNESS_BARCODE",
                    "OP30_BUCKLE_BARCODE",
                    "OP30_CTR_BUCKLE_BARCODE",
                    "TEST_PAIR_SERIAL"
                ];

                foreach (var col in barcodeColumns)
                {
                    await CreateIndexIfNotExistsAsync(conn, "TABLE_MAIN", col, $"IX_TABLE_MAIN_{col}");
                }

                // TABLE_PART.PartNo 인덱스
                await CreateIndexIfNotExistsAsync(conn, "TABLE_PART", "PartNo", "IX_TABLE_PART_PartNo");

                _indexChecked = true;
                LogHelper.Instance.Log("SqlHelper", "인덱스 확인/생성 완료");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", "인덱스 확인/생성 실패", ex);
            }
        }

        /// <summary>
        /// 개별 인덱스 존재 확인 및 생성
        /// </summary>
        private static async Task CreateIndexIfNotExistsAsync(SqlConnection conn, string tableName, string columnName, string indexName)
        {
            try
            {
                // 인덱스 존재 여부 확인
                var checkSql = @"
                    SELECT COUNT(*) FROM sys.indexes
                    WHERE name = @IndexName AND object_id = OBJECT_ID(@TableName)";

                using var checkCmd = new SqlCommand(checkSql, conn);
                checkCmd.Parameters.AddWithValue("@IndexName", indexName);
                checkCmd.Parameters.AddWithValue("@TableName", tableName);

                var exists = Convert.ToInt32(await checkCmd.ExecuteScalarAsync()) > 0;

                if (exists)
                {
                    LogHelper.Instance.Log("SqlHelper", $"인덱스 이미 존재: {indexName}");
                    return;
                }

                // 인덱스 생성
                var createSql = $"CREATE NONCLUSTERED INDEX [{indexName}] ON [{tableName}]([{columnName}])";
                using var createCmd = new SqlCommand(createSql, conn);
                await createCmd.ExecuteNonQueryAsync();

                LogHelper.Instance.Log("SqlHelper", $"인덱스 생성 완료: {indexName} ON {tableName}({columnName})");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", $"인덱스 생성 실패: {indexName}", ex);
            }
        }

        /// <summary>
        /// 쿼리 실행 (DataTable 반환)
        /// </summary>
        public static async Task<DataTable> ExecuteQueryAsync(string sql, params SqlParameter[] parameters)
        {
            if (string.IsNullOrEmpty(_connectionString))
                return new DataTable();

            var dt = new DataTable();
            try
            {
                using var conn = new SqlConnection(_connectionString);
                using var cmd = new SqlCommand(sql, conn);
                cmd.CommandTimeout = 30;

                if (parameters != null)
                    cmd.Parameters.AddRange(parameters);

                await conn.OpenAsync();
                using var reader = await cmd.ExecuteReaderAsync();
                dt.Load(reader);
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", $"ExecuteQueryAsync 오류: {ex.Message}", ex);
            }
            return dt;
        }

        /// <summary>
        /// 단일 값 조회
        /// </summary>
        public static async Task<object?> ExecuteScalarAsync(string sql, params SqlParameter[] parameters)
        {
            if (string.IsNullOrEmpty(_connectionString)) return null;

            try
            {
                using var conn = new SqlConnection(_connectionString);
                using var cmd = new SqlCommand(sql, conn);
                cmd.CommandTimeout = 30;

                if (parameters != null)
                    cmd.Parameters.AddRange(parameters);

                await conn.OpenAsync();
                return await cmd.ExecuteScalarAsync();
            }
            catch
            {
                return null;
            }
        }

        /// <summary>
        /// INSERT/UPDATE/DELETE 실행
        /// </summary>
        public static async Task<int> ExecuteNonQueryAsync(string sql, params SqlParameter[] parameters)
        {
            if (string.IsNullOrEmpty(_connectionString))
            {
                LogHelper.Instance.Log("SqlHelper", "ExecuteNonQueryAsync: ConnectionString이 비어있음");
                return 0;
            }

            try
            {
                using var conn = new SqlConnection(_connectionString);
                using var cmd = new SqlCommand(sql, conn);
                cmd.CommandTimeout = 30;

                if (parameters != null)
                    cmd.Parameters.AddRange(parameters);

                await conn.OpenAsync();
                var result = await cmd.ExecuteNonQueryAsync();
                LogHelper.Instance.Log("SqlHelper", $"ExecuteNonQueryAsync: affected={result}");
                return result;
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", $"ExecuteNonQueryAsync 오류: {ex.Message}", ex);
                return 0;
            }
        }

        /// <summary>
        /// INSERT/UPDATE/DELETE 실행 (재시도 포함)
        /// 최대 5회 재시도, 각 재시도 간 1초 대기
        /// </summary>
        public static async Task<int> ExecuteNonQueryWithRetryAsync(string sql, int maxRetries = 5, params SqlParameter[] parameters)
        {
            if (string.IsNullOrEmpty(_connectionString))
            {
                LogHelper.Instance.Log("SqlHelper", "ExecuteNonQueryWithRetryAsync: ConnectionString이 비어있음");
                return 0;
            }

            Exception? lastException = null;

            for (int attempt = 1; attempt <= maxRetries; attempt++)
            {
                try
                {
                    using var conn = new SqlConnection(_connectionString);
                    using var cmd = new SqlCommand(sql, conn);
                    cmd.CommandTimeout = 30;

                    if (parameters != null)
                        cmd.Parameters.AddRange(parameters);

                    await conn.OpenAsync();
                    var result = await cmd.ExecuteNonQueryAsync();

                    if (attempt > 1)
                    {
                        LogHelper.Instance.Log("SqlHelper", $"ExecuteNonQueryWithRetryAsync: 재시도 {attempt}회 성공, affected={result}");
                    }
                    else
                    {
                        LogHelper.Instance.Log("SqlHelper", $"ExecuteNonQueryWithRetryAsync: affected={result}");
                    }

                    return result;
                }
                catch (Exception ex)
                {
                    lastException = ex;
                    LogHelper.Instance.LogError("SqlHelper", $"ExecuteNonQueryWithRetryAsync: 재시도 {attempt}/{maxRetries} 실패 - {ex.Message}", ex);

                    // 마지막 시도가 아니면 대기 후 재시도
                    if (attempt < maxRetries)
                    {
                        await Task.Delay(1000); // 1초 대기
                    }
                }
            }

            // 모든 재시도 실패
            LogHelper.Instance.LogError("SqlHelper", $"ExecuteNonQueryWithRetryAsync: {maxRetries}회 재시도 모두 실패", lastException);
            return 0;
        }

        /// <summary>
        /// TABLE_MAIN 바코드/시리얼 관련 컬럼 목록 캐시 (최적화됨)
        /// </summary>
        public static async Task<List<string>> GetSearchableColumnsAsync()
        {
            if (_searchableColumns != null)
                return _searchableColumns;

            _searchableColumns = [];

            // BARCODE, Serial 관련 컬럼만 검색 (성능 최적화)
            const string sql = @"
                SELECT COLUMN_NAME
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_NAME = 'TABLE_MAIN'
                AND DATA_TYPE IN ('char', 'varchar', 'nchar', 'nvarchar')
                AND (COLUMN_NAME LIKE '%BARCODE%'
                     OR COLUMN_NAME LIKE '%Serial%'
                     OR COLUMN_NAME = 'PartNo')
                ORDER BY ORDINAL_POSITION";

            var dt = await ExecuteQueryAsync(sql);
            foreach (DataRow row in dt.Rows)
            {
                _searchableColumns.Add(row["COLUMN_NAME"].ToString() ?? "");
            }

            LogHelper.Instance.Log("SqlHelper", $"바코드/시리얼 검색 컬럼: {string.Join(", ", _searchableColumns)}");
            return _searchableColumns;
        }

        /// <summary>
        /// 바코드로 파트 조회 (LoadPart)
        /// 최적화: BARCODE/Serial 컬럼만 검색, UNION 사용하여 인덱스 활용
        /// </summary>
        public static async Task<PartInfo?> LoadPartAsync(string barcode)
        {
            if (string.IsNullOrEmpty(barcode)) return null;

            // 최초 1회 인덱스 확인/생성
            await EnsureIndexesAsync();

            LogHelper.Instance.Log("SqlHelper", $"LoadPartAsync 시작: barcode={barcode}");

            var columns = await GetSearchableColumnsAsync();
            LogHelper.Instance.Log("SqlHelper", $"검색 컬럼 수: {columns.Count}");
            if (columns.Count == 0)
            {
                LogHelper.Instance.Log("SqlHelper", "검색 가능 컬럼 없음 - SQL Server 연결 확인 필요");
                return null;
            }

            // UNION ALL로 각 컬럼별 검색 (각각 인덱스 활용 가능)
            var unionQueries = columns.Select(col =>
                $"SELECT * FROM TABLE_MAIN WHERE [{col}] = @Barcode");
            var sql = $"SELECT TOP 1 * FROM ({string.Join(" UNION ALL ", unionQueries)}) AS T ORDER BY SerialNo DESC";

            LogHelper.Instance.Log("SqlHelper", $"Query: UNION ALL {columns.Count}개 컬럼 검색");

            var dt = await ExecuteQueryAsync(sql, new SqlParameter("@Barcode", barcode));
            LogHelper.Instance.Log("SqlHelper", $"RecordCount: {dt.Rows.Count}");
            if (dt.Rows.Count == 0) return null;

            var row = dt.Rows[0];
            return new PartInfo
            {
                PartNo = NullCheck(row, "PartNo"),
                PartName = NullCheck(row, "PartName"),
                SerialNo = NullCheck(row, "SerialNo").Replace(" ", ""),
                Op10Decision = NullCheck(row, "Op10_Decision"),
                Op20Decision = NullCheck(row, "Op20_Decision"),
                Op30Decision = NullCheck(row, "Op30_Decision"),
                Op40Decision = NullCheck(row, "Op40_Decision"),
                Op50Decision = NullCheck(row, "Op50_Decision"),
                Op60Decision = NullCheck(row, "Op60_Decision")
            };
        }

        /// <summary>
        /// 시리얼로 NG 체크 (LoadPartNG)
        /// </summary>
        public static async Task<PartNgResult> LoadPartNgAsync(string serialNo)
        {
            var result = new PartNgResult();
            if (string.IsNullOrEmpty(serialNo)) return result;

            var sql = "SELECT * FROM TABLE_MAIN WHERE SerialNo = @SerialNo";
            var dt = await ExecuteQueryAsync(sql, new SqlParameter("@SerialNo", serialNo));

            if (dt.Rows.Count != 1) return result;

            var row = dt.Rows[0];
            var partNo = NullCheck(row, "PartNo");

            result.PartNo = partNo;
            result.PartName = NullCheck(row, "PartName");
            result.SerialNo = NullCheck(row, "SerialNo");

            // NG 스텝 체크
            if (partNo.Contains("89600") || partNo.Contains("89AC2") || partNo.Contains("89A60"))
            {
                // B측 (RH)
                result.Side = "B";
                CheckNgSteps(row, result, ["Op10", "Op20", "Op30", "Op40", "Op60"]);
            }
            else if (partNo.Contains("89500") || partNo.Contains("89AC1") || partNo.Contains("89A50"))
            {
                // A측 (LH)
                result.Side = "A";
                CheckNgSteps(row, result, ["Op10", "Op20", "Op40", "Op50", "Op60"]);
            }

            return result;
        }

        private static void CheckNgSteps(DataRow row, PartNgResult result, string[] opNames)
        {
            foreach (var op in opNames)
            {
                var decision = NullCheck(row, $"{op}_Decision");
                if (decision != "OK" && !string.IsNullOrEmpty(decision))
                {
                    result.NgSteps.Add(op.ToUpper());
                    result.IsNg = true;
                }
            }
        }

        /// <summary>
        /// 검사 결과 저장 (VB 원본과 동일한 컬럼명 사용)
        /// SQL Server 연결 실패 시 최대 5회 재시도
        /// 5회 재시도 후에도 실패하면 MDB에만 저장
        /// </summary>
        public static async Task<bool> SaveResultAsync(string serialNo, string pairSerial, MeasureData data, string side)
        {
            LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync 시작: Serial={serialNo}, Side={side}");

            // VB 원본과 동일한 컬럼명 사용
            var sql = @"
                UPDATE Table_Main SET
                    Test_Date = @TestDate,
                    Test_Start_Time = @StartTime,
                    Test_End_Time = @EndTime,
                    Test_Pair_Serial = @PairSerial,
                    TEST_FWD_1_ANGLE = @FwdAngle1,
                    TEST_FWD_2_ANGLE = @FwdAngle2,
                    TEST_FWD_3_ANGLE = @FwdAngle3,
                    TEST_FWD_4_ANGLE = @FwdAngle4,
                    TEST_FWD_5_ANGLE = @FwdAngle5,
                    TEST_BWD_1_ANGLE = @BwdAngle1,
                    TEST_BWD_2_ANGLE = @BwdAngle2,
                    TEST_BWD_3_ANGLE = @BwdAngle3,
                    TEST_BWD_4_ANGLE = @BwdAngle4,
                    TEST_BWD_5_ANGLE = @BwdAngle5,
                    TEST_END_1_ANGLE = @EndAngle1,
                    TEST_END_2_ANGLE = @EndAngle2,
                    TEST_END_3_ANGLE = @EndAngle3,
                    TEST_END_4_ANGLE = @EndAngle4,
                    TEST_END_5_ANGLE = @EndAngle5,
                    TEST_FWD_1_DIFF_ANGLE = @FwdDiff1,
                    TEST_FWD_2_DIFF_ANGLE = @FwdDiff2,
                    TEST_FWD_3_DIFF_ANGLE = @FwdDiff3,
                    TEST_FWD_4_DIFF_ANGLE = @FwdDiff4,
                    TEST_FWD_5_DIFF_ANGLE = @FwdDiff5,
                    TEST_BWD_1_DIFF_ANGLE = @BwdDiff1,
                    TEST_BWD_2_DIFF_ANGLE = @BwdDiff2,
                    TEST_BWD_3_DIFF_ANGLE = @BwdDiff3,
                    TEST_BWD_4_DIFF_ANGLE = @BwdDiff4,
                    TEST_BWD_5_DIFF_ANGLE = @BwdDiff5,
                    TEST_END_1_DIFF_ANGLE = @EndDiff1,
                    TEST_END_2_DIFF_ANGLE = @EndDiff2,
                    TEST_END_3_DIFF_ANGLE = @EndDiff3,
                    TEST_END_4_DIFF_ANGLE = @EndDiff4,
                    TEST_END_5_DIFF_ANGLE = @EndDiff5,
                    TEST_FWD_DIFF_DECISION = @FwdDiffDec,
                    TEST_BWD_DIFF_DECISION = @BwdDiffDec,
                    TEST_END_DIFF_DECISION = @EndDiffDec,
                    TEST_LEVER_TQ = @LeverTq,
                    TEST_LEVER_TQ_DECISION = @LeverDec
                WHERE SerialNo = @SerialNo";

            // A측/B측에 따라 데이터 선택
            string leverVal, leverDec;
            double angleFwd, angleBwd, angleEnd;

            if (side == "A")
            {
                // 각도센서 직접 측정값 (FWD=0, BWD=1, END=2)
                angleFwd = data.AngleMeasuredA[0];
                angleBwd = data.AngleMeasuredA[1];
                angleEnd = data.AngleMeasuredA[2];
                leverVal = data.ValueLever.ToString("F1");
                leverDec = data.DecLeverA;
            }
            else
            {
                // 각도센서 직접 측정값 (FWD=0, BWD=1, END=2)
                angleFwd = data.AngleMeasuredB[0];
                angleBwd = data.AngleMeasuredB[1];
                angleEnd = data.AngleMeasuredB[2];
                leverVal = data.ValueLeverB.ToString("F1");
                leverDec = data.DecLeverB;
            }

            // 각도센서 값 저장 (1번 컬럼만 사용, 나머지는 빈값)
            var parameters = new List<SqlParameter>
            {
                new("@SerialNo", serialNo),
                new("@PairSerial", pairSerial ?? ""),
                new("@TestDate", DateTime.Now.ToString("yyyy-MM-dd")),
                new("@StartTime", data.StartTime ?? ""),
                new("@EndTime", DateTime.Now.ToString("HH:mm:ss")),
                // FWD 각도센서 값 (1번만 사용)
                new("@FwdAngle1", angleFwd.ToString("F1")),
                new("@FwdAngle2", ""),
                new("@FwdAngle3", ""),
                new("@FwdAngle4", ""),
                new("@FwdAngle5", ""),
                // BWD 각도센서 값 (1번만 사용)
                new("@BwdAngle1", angleBwd.ToString("F1")),
                new("@BwdAngle2", ""),
                new("@BwdAngle3", ""),
                new("@BwdAngle4", ""),
                new("@BwdAngle5", ""),
                // END 각도센서 값 (1번만 사용)
                new("@EndAngle1", angleEnd.ToString("F1")),
                new("@EndAngle2", ""),
                new("@EndAngle3", ""),
                new("@EndAngle4", ""),
                new("@EndAngle5", ""),
                // DIFF (5포인트)
                new("@FwdDiff1", data.ValDiffFwd[0] ?? ""),
                new("@FwdDiff2", data.ValDiffFwd[1] ?? ""),
                new("@FwdDiff3", data.ValDiffFwd[2] ?? ""),
                new("@FwdDiff4", data.ValDiffFwd[3] ?? ""),
                new("@FwdDiff5", data.ValDiffFwd[4] ?? ""),
                new("@BwdDiff1", data.ValDiffBwd[0] ?? ""),
                new("@BwdDiff2", data.ValDiffBwd[1] ?? ""),
                new("@BwdDiff3", data.ValDiffBwd[2] ?? ""),
                new("@BwdDiff4", data.ValDiffBwd[3] ?? ""),
                new("@BwdDiff5", data.ValDiffBwd[4] ?? ""),
                new("@EndDiff1", data.ValDiffEnd[0] ?? ""),
                new("@EndDiff2", data.ValDiffEnd[1] ?? ""),
                new("@EndDiff3", data.ValDiffEnd[2] ?? ""),
                new("@EndDiff4", data.ValDiffEnd[3] ?? ""),
                new("@EndDiff5", data.ValDiffEnd[4] ?? ""),
                // DIFF 판정 (총합)
                new("@FwdDiffDec", GetTotalDecision(data.DecDiffFwd)),
                new("@BwdDiffDec", GetTotalDecision(data.DecDiffBwd)),
                new("@EndDiffDec", GetTotalDecision(data.DecDiffEnd)),
                // 레버
                new("@LeverTq", leverVal),
                new("@LeverDec", leverDec ?? "")
            };

            // SQL Server 저장 시도 (최대 5회 재시도)
            const int maxRetries = 5;
            bool serverSuccess = false;
            Exception? lastException = null;

            for (int attempt = 1; attempt <= maxRetries; attempt++)
            {
                try
                {
                    var affected = await ExecuteNonQueryAsync(sql, parameters.ToArray());
                    serverSuccess = affected > 0;

                    if (serverSuccess)
                    {
                        if (attempt > 1)
                        {
                            LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync SQL Server 저장 성공 (재시도 {attempt}회): Serial={serialNo}");
                        }
                        else
                        {
                            LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync SQL Server 저장 성공: Serial={serialNo}");
                        }
                        break; // 성공 시 루프 종료
                    }
                    else
                    {
                        // affected = 0 (레코드 없음 또는 업데이트 실패)
                        LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync SQL Server 저장 실패 (affected=0): Serial={serialNo}, 시도={attempt}/{maxRetries}");
                        if (attempt < maxRetries)
                        {
                            await Task.Delay(1000); // 1초 대기 후 재시도
                        }
                    }
                }
                catch (Exception ex)
                {
                    lastException = ex;
                    LogHelper.Instance.LogError("SqlHelper", $"SaveResultAsync SQL Server 저장 오류 (시도 {attempt}/{maxRetries}): Serial={serialNo}, {ex.Message}", ex);

                    // 마지막 시도가 아니면 대기 후 재시도
                    if (attempt < maxRetries)
                    {
                        await Task.Delay(1000); // 1초 대기
                    }
                }
            }

            // 5회 재시도 후에도 실패한 경우
            if (!serverSuccess)
            {
                LogHelper.Instance.LogError("SqlHelper", $"SaveResultAsync SQL Server 저장 최종 실패 ({maxRetries}회 재시도 모두 실패): Serial={serialNo}", lastException);
            }

            // 로컬 Access DB에 저장 (항상 실행, SQL Server 성공 여부와 관계없이)
            // 5회 재시도 후에도 SQL Server 실패 시 MDB에만 저장됨
            try
            {
                // A=LH, B=RH - 각도센서 값 별도 저장
                // FwdVal/EndVal/BwdVal은 레이저 거리값 (DIFF용)
                string[] fwdLen = side == "A" ? data.ValFwdLenA : data.ValFwdLenB;
                string[] endLen = side == "A" ? data.ValEndLenA : data.ValEndLenB;
                string[] bwdLen = side == "A" ? data.ValBwdLenA : data.ValBwdLenB;

                // 각도센서 값 (LH/RH 각각)
                string angleFwdLH = data.AngleMeasuredA[0].ToString("F1");
                string angleBwdLH = data.AngleMeasuredA[1].ToString("F1");
                string angleEndLH = data.AngleMeasuredA[2].ToString("F1");
                string angleFwdRH = data.AngleMeasuredB[0].ToString("F1");
                string angleBwdRH = data.AngleMeasuredB[1].ToString("F1");
                string angleEndRH = data.AngleMeasuredB[2].ToString("F1");

                LocalDbHelper.InsertRecord(
                    data.SerialNoA, data.SerialNoB,  // SerialNoLH, SerialNoRH
                    data.PartNoA, data.PartNoB,      // PartNoLH, PartNoRH
                    side, data.FinalDecision,
                    fwdLen, endLen, bwdLen,  // 레이저 거리값
                    data.ValDiffFwd, data.ValDiffEnd, data.ValDiffBwd,
                    leverVal, serverSuccess,
                    angleFwdLH, angleBwdLH, angleEndLH,  // LH 각도센서
                    angleFwdRH, angleBwdRH, angleEndRH); // RH 각도센서

                if (serverSuccess)
                {
                    LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync 로컬 DB 백업 완료: Serial={serialNo}");
                }
                else
                {
                    LogHelper.Instance.Log("SqlHelper", $"SaveResultAsync 로컬 DB 저장 완료 (SQL Server 실패로 인한 단독 저장): Serial={serialNo}");
                }
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("SqlHelper", $"로컬 DB 저장 실패: {ex.Message}", ex);
            }

            return serverSuccess;
        }

        /// <summary>
        /// DIFF 판정 배열에서 총합 판정 계산
        /// </summary>
        private static string GetTotalDecision(string[] decArray)
        {
            // 5포인트 (0~4)
            for (int i = 0; i < 5; i++)
            {
                if (i < decArray.Length && decArray[i] == "NG")
                    return "NG";
            }
            return "OK";
        }

        /// <summary>
        /// TABLE_PART에서 사양 정보 조회
        /// VB.NET 원본: SELECT * FROM TABLE_PART WHERE PARTNO LIKE '%[앞11자리]%'
        /// </summary>
        public static async Task<PartSpec?> LoadPartSpecAsync(string partNo)
        {
            if (string.IsNullOrEmpty(partNo)) return null;

            // PartNo 앞 11자리로 검색 (VB.NET: Mid(strPart, 1, 11))
            var searchKey = partNo.Length >= 11 ? partNo[..11] : partNo;
            var sql = "SELECT * FROM TABLE_PART WHERE PartNo LIKE @PartNo";

            LogHelper.Instance.Log("SqlHelper", $"LoadPartSpecAsync: partNo={partNo}, searchKey={searchKey}");

            var dt = await ExecuteQueryAsync(sql, new SqlParameter("@PartNo", $"%{searchKey}%"));
            LogHelper.Instance.Log("SqlHelper", $"TABLE_PART RecordCount: {dt.Rows.Count}");

            if (dt.Rows.Count != 1) return null;

            var row = dt.Rows[0];
            return new PartSpec
            {
                PartNo = NullCheck(row, "PartNo").Trim(),
                Position = NullCheck(row, "Position").Replace(" ", ""),
                Position2 = NullCheck(row, "Position2").Replace(" ", ""),
                Option = NullCheck(row, "Option").Replace(" ", "")
            };
        }

        private static string NullCheck(DataRow row, string columnName)
        {
            try
            {
                if (row.Table.Columns.Contains(columnName))
                    return row[columnName]?.ToString() ?? "";
            }
            catch { }
            return "";
        }

