    /// <summary>
    /// 파트 정보
    /// </summary>
    public class PartInfo
    {
        public string PartNo { get; set; } = "";
        public string PartName { get; set; } = "";
        public string SerialNo { get; set; } = "";
        public string Op10Decision { get; set; } = "";
        public string Op20Decision { get; set; } = "";
        public string Op30Decision { get; set; } = "";
        public string Op40Decision { get; set; } = "";
        public string Op50Decision { get; set; } = "";
        public string Op60Decision { get; set; } = "";

        /// <summary>
        /// A측(LH) 파트인지 확인
        /// </summary>
        public bool IsSideA => PartNo.Contains("89500") || PartNo.Contains("89AC1") || PartNo.Contains("89A50");

        /// <summary>
        /// B측(RH) 파트인지 확인
        /// </summary>
        public bool IsSideB => PartNo.Contains("89600") || PartNo.Contains("89AC2") || PartNo.Contains("89A60");
    }

    /// <summary>
    /// NG 체크 결과
    /// </summary>
    public class PartNgResult
    {
        public bool IsNg { get; set; }
        public string Side { get; set; } = "";
        public string PartNo { get; set; } = "";
        public string PartName { get; set; } = "";
        public string SerialNo { get; set; } = "";
        public List<string> NgSteps { get; } = [];

        public string NgMessage => NgSteps.Count > 0 ? $"NG: {string.Join(", ", NgSteps)}" : "";
    }

    /// <summary>
    /// 파트 사양 정보 (TABLE_PART)
    /// </summary>
    public class PartSpec
    {
        public string PartNo { get; set; } = "";
        public string Position { get; set; } = "";   // LH, RH
        public string Position2 { get; set; } = "";  // LHD, RHD
        public string Option { get; set; } = "";     // 2-2P, 2-3P, 3-2P, 3-3P, 3-WAV

        /// <summary>
        /// A측(LH) 파트인지 확인
        /// </summary>
        public bool IsSideA => PartNo.Contains("89500") || PartNo.Contains("89AC1") || PartNo.Contains("89A50");

        /// <summary>
        /// B측(RH) 파트인지 확인
        /// </summary>
        public bool IsSideB => PartNo.Contains("89600") || PartNo.Contains("89AC2") || PartNo.Contains("89A60");
    }

    // FrmBarcode용 추가 메서드들
    public static partial class SqlHelper
    {
        /// <summary>
        /// Table_Part에서 모든 PartNo 로드
        /// </summary>
        public static List<string> LoadAllPartNo()
        {
            var result = new List<string>();
            try
            {
                using var conn = new SqlConnection(_connectionString);
                conn.Open();
                using var cmd = new SqlCommand(
                    "SELECT PartNo FROM Table_Part ORDER BY PartNo", conn);
                using var reader = cmd.ExecuteReader();
                while (reader.Read())
                {
                    var partNo = reader["PartNo"]?.ToString()?.Trim() ?? "";
                    if (!string.IsNullOrEmpty(partNo))
                        result.Add(partNo);
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"LoadAllPartNo Error: {ex.Message}");
            }
            return result;
        }

        /// <summary>
        /// 모든 Table_Color_* 테이블에서 ColorCode 로드 (중복 제거)
        /// </summary>
        public static List<string> LoadAllColorCodes()
        {
            var result = new HashSet<string>();

            // 이미지에서 확인된 테이블 목록
            string[] colorTables = {
                "Table_Color_2ND_2P_LH_LHD",
                "Table_Color_2ND_2P_LH_RHD",
                "Table_Color_2ND_2P_RH_LHD",
                "Table_Color_2ND_2P_RH_RHD",
                "Table_Color_2ND_3P_LH",
                "Table_Color_2ND_3P_RH",
                "Table_Color_3RD_2P_LH",
                "Table_Color_3RD_2P_RH",
                "Table_Color_3RD_3P_LH",
                "Table_Color_3RD_3P_RH",
                "Table_Color_3RD_WAV_LH",
                "Table_Color_3RD_WAV_LHD",
                "Table_Color_3RD_WAV_RH",
                "Table_Color_3RD_WAV_RHD"
            };

            try
            {
                using var conn = new SqlConnection(_connectionString);
                conn.Open();

                foreach (var tableName in colorTables)
                {
                    try
                    {
                        using var cmd = new SqlCommand(
                            $"SELECT ColorCode FROM [{tableName}]", conn);
                        using var reader = cmd.ExecuteReader();
                        while (reader.Read())
                        {
                            var colorCode = reader["ColorCode"]?.ToString()?.Trim() ?? "";
                            if (!string.IsNullOrEmpty(colorCode))
                                result.Add(colorCode);
                        }
                    }
                    catch
                    {
                        // 테이블이 없으면 무시
                    }
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"LoadAllColorCodes Error: {ex.Message}");
            }

            return result.OrderBy(x => x).ToList();
        }

        /// <summary>
        /// Table_Part에서 PartName 조회
        /// </summary>
        public static string GetPartName(string partNo)
        {
            try
            {
                using var conn = new SqlConnection(_connectionString);
                conn.Open();
                using var cmd = new SqlCommand(
                    "SELECT PartName FROM Table_Part WHERE PartNo = @PartNo", conn);
                cmd.Parameters.AddWithValue("@PartNo", partNo);
                var result = cmd.ExecuteScalar();
                return result?.ToString()?.Trim() ?? "";
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"GetPartName Error: {ex.Message}");
                return "";
            }
        }
    }
}

