+        /// <summary>
+        /// Table_Main에서 시리얼번호로 서브부품 컬럼 값 조회
+        /// columnNames: "/" 구분 컬럼명 (예: "COL1/COL2/COL3")
+        /// 반환: 값이 있는 컬럼만 "#값1#값2" 형태로 반환, 전부 빈값이면 "" 반환
+        /// </summary>
+        public static string GetSubPartData(string serialNo, string columnNames)
+        {
+            if (string.IsNullOrWhiteSpace(serialNo) || string.IsNullOrWhiteSpace(columnNames))
+                return "";
+
+            try
+            {
+                var columns = columnNames.Split('/').Select(c => c.Trim()).Where(c => c.Length > 0).ToArray();
+                if (columns.Length == 0) return "";
+
+                string selectCols = string.Join(", ", columns.Select(c => $"[{c}]"));
+                string sql = $"SELECT {selectCols} FROM Table_Main WHERE SerialNo = @SerialNo";
+
+                using var conn = new SqlConnection(_connectionString);
+                conn.Open();
+                using var cmd = new SqlCommand(sql, conn);
+                cmd.Parameters.AddWithValue("@SerialNo", serialNo);
+
+                using var reader = cmd.ExecuteReader();
+                if (!reader.Read()) return "";
+
+                var sb = new System.Text.StringBuilder();
+                for (int i = 0; i < columns.Length; i++)
+                {
+                    string val = reader.IsDBNull(i) ? "" : reader.GetValue(i)?.ToString()?.Trim() ?? "";
+                    if (!string.IsNullOrEmpty(val))
+                        sb.Append('#').Append(val);
+                }
+                return sb.ToString();
+            }
+            catch (Exception ex)
+            {
+                LogHelper.Instance.LogError("SqlHelper", $"GetSubPartData 오류: serial={serialNo}, columns={columnNames}", ex);
+                return "";
+            }
+        }
     }
